public String chompBalanced(char open, char close) {
    int start = -1;
    int end = -1;
    int depth = 0;
    char last = 0;
    boolean inQuotes = false;
    final char SINGLE_QUOTE = '\'';
    final char DOUBLE_QUOTE = '"';

    do {
        if (isEmpty()) break;
        Character c = consume();
        if (c == null) break;
        if (!inQuotes && (last == 0 || last != '\\')) {
            if (c == open) {
                depth++;
                if (start == -1)
                    start = pos;
            }
            else if (c == close)
                depth--;
        }
        if ((c == SINGLE_QUOTE || c == DOUBLE_QUOTE) && (last == 0 || last != '\\')) {
            inQuotes = !inQuotes;
        }

        if (depth > 0 && last != 0)
            end = pos; // don't include the outer match pair in the return
        last = c;
    } while (depth > 0);
    return (end >= 0) ? queue.substring(start, end) : "";
}
